// adsListEnvelope mirrors the shape lalafo's /v3/ads collection endpoints
// return: a domain array under "items" alongside "_meta"/"_links" sidecars.
// The formatters must project the inner rows, not dump the wrapper object.
const adsListEnvelope = `{
  "items": [
    {"id": 114491517, "title": "iPhone 13", "price": 25000, "city": "Bishkek"},
    {"id": 114491600, "title": "Samsung S21", "price": 18000, "city": "Osh"}
  ],
  "_meta": {"total_count": 2, "per_page": 20},
  "_links": {"self": "/v3/ads"}
}`

// TestUnwrapListEnvelope covers the shared locator that CSV/plain/table
// rendering uses to reach the inner rows of a list-envelope response.
func TestUnwrapListEnvelope(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name     string
		input    string
		wantOK   bool
		wantLen  int
		firstID  float64
		hasFirst bool
	}{
		{
			name:     "ads items envelope with metadata siblings",
			input:    adsListEnvelope,
			wantOK:   true,
			wantLen:  2,
			firstID:  114491517,
			hasFirst: true,
		},
		{
			name:   "stripe-style data wrapper",
			input:  `{"object":"list","data":[{"id":1},{"id":2},{"id":3}]}`,
			wantOK: true, wantLen: 3,
		},
		{
			name:   "single detail object is not an envelope",
			input:  `{"id":114491517,"title":"iPhone 13","price":25000}`,
			wantOK: false,
		},
		{
			name:   "bare array is not an envelope object",
			input:  `[{"id":1},{"id":2}]`,
			wantOK: false,
		},
		{
			name:   "scalar count response is not an envelope",
			input:  `{"ads_count":123456,"feed-name":"main","feed-id":7}`,
			wantOK: false,
		},
		{
			// An ad detail carries nested object-arrays (images, params). It
			// must NOT be mistaken for a list envelope, or `ads get` would
			// render a table of the sub-array instead of the ad.
			name:   "detail object with nested arrays is not an envelope",
			input:  `{"id":114491517,"title":"iPhone","images":[{"id":9,"url":"u"}],"params":[{"name":"year","value":2020}]}`,
			wantOK: false,
		},
		{
			name:   "detail object with a single nested array is not an envelope",
			input:  `{"id":114491517,"title":"iPhone","images":[{"id":9,"url":"u"}]}`,
			wantOK: false,
		},
	}
	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			got, ok := unwrapListEnvelope(json.RawMessage(tc.input))
			if ok != tc.wantOK {
				t.Fatalf("unwrapListEnvelope ok = %v, want %v (raw=%s)", ok, tc.wantOK, got)
			}
			if !ok {
				return
			}
			var rows []map[string]any
			if err := json.Unmarshal(got, &rows); err != nil {
				t.Fatalf("unwrapped payload is not an array: %v (raw=%s)", err, got)
			}
			if len(rows) != tc.wantLen {
				t.Errorf("row count = %d, want %d", len(rows), tc.wantLen)
			}
			if tc.hasFirst {
				if id, _ := rows[0]["id"].(float64); id != tc.firstID {
					t.Errorf("rows[0].id = %v, want %v", rows[0]["id"], tc.firstID)
				}
			}
		})
	}
}

// TestListItemsForTabularOutput pins the row-resolution used by printOutput's
// table branch: bare arrays and list envelopes both yield rows; single objects
// and empty collections fall back (false) so the caller keeps its raw path.
func TestListItemsForTabularOutput(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name    string
		input   string
		wantOK  bool
		wantLen int
	}{
		{"bare array", `[{"id":1},{"id":2}]`, true, 2},
		{"list envelope", adsListEnvelope, true, 2},
		{"single object", `{"id":1,"title":"x"}`, false, 0},
		{"empty envelope", `{"items":[],"_meta":{}}`, false, 0},
		{"empty bare array", `[]`, false, 0},
	}
	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			items, ok := listItemsForTabularOutput(json.RawMessage(tc.input))
			if ok != tc.wantOK {
				t.Fatalf("ok = %v, want %v", ok, tc.wantOK)
			}
			if ok && len(items) != tc.wantLen {
				t.Errorf("len = %d, want %d", len(items), tc.wantLen)
			}
		})
	}
}

