// TestDetailResponseItemCount covers the provenance counter for single-resource
// fetches (ads get / ads get-count): a non-empty detail object must report 1,
// not 0 (the R1 regression — a successful `ads get <id>` printed "0 results
// (live)" directly above the ad it just fetched, because the old inline count
// unmarshaled the object into a []json.RawMessage that always came back empty).
// Arrays and list envelopes still report their row count; JSON null, an empty
// object, and an empty collection report 0.
func TestDetailResponseItemCount(t *testing.T) {
	t.Parallel()
	cases := []struct {
		name string
		in   string
		want int
	}{
		{"single ad detail object", `{"id":114121330,"title":"iPhone 13","price":25000}`, 1},
		{"detail object with nested arrays", `{"id":1,"images":[{"id":9}],"params":[{"name":"year"}]}`, 1},
		{"scalar count aggregate", `{"ads_count":123456,"feed-name":"main","feed-id":7}`, 1},
		{"list envelope", adsListEnvelope, 2},
		{"bare array", `[{"id":1},{"id":2},{"id":3}]`, 3},
		{"empty object", `{}`, 0},
		{"json null", `null`, 0},
		{"empty array", `[]`, 0},
		{"empty envelope", `{"items":[],"_meta":{}}`, 0},
	}
	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			if got := detailResponseItemCount(json.RawMessage(tc.in)); got != tc.want {
				t.Errorf("detailResponseItemCount(%s) = %d, want %d", tc.in, got, tc.want)
			}
		})
	}
}

// TestPrintCSV_ListEnvelope is the F3 regression: `ads list --csv` must emit a
// real CSV of the inner rows, not a single-line dump of the wrapper object.
func TestPrintCSV_ListEnvelope(t *testing.T) {
	t.Parallel()
	var buf bytes.Buffer
	if err := printCSV(&buf, json.RawMessage(adsListEnvelope)); err != nil {
		t.Fatalf("printCSV: %v", err)
	}
	records, err := csv.NewReader(strings.NewReader(buf.String())).ReadAll()
	if err != nil {
		t.Fatalf("output is not valid CSV: %v\noutput:\n%s", err, buf.String())
	}
	// Header + 2 data rows.
	if len(records) != 3 {
		t.Fatalf("record count = %d, want 3 (header + 2 rows)\noutput:\n%s", len(records), buf.String())
	}
	wantHeader := []string{"city", "id", "price", "title"}
	if strings.Join(records[0], ",") != strings.Join(wantHeader, ",") {
		t.Errorf("header = %v, want %v", records[0], wantHeader)
	}
	// A wrapper dump would have surfaced "_meta"/"_links" as columns; a real
	// projection carries the ad titles as cell values.
	if !strings.Contains(buf.String(), "iPhone 13") || !strings.Contains(buf.String(), "Samsung S21") {
		t.Errorf("expected ad titles in CSV rows, got:\n%s", buf.String())
	}
	if strings.Contains(buf.String(), "_meta") || strings.Contains(buf.String(), "_links") {
		t.Errorf("wrapper keys leaked into CSV output:\n%s", buf.String())
	}
}

// TestPrintCSV_NestedCellJSONEncoded is the F5 regression: nested objects/arrays
// must serialize as JSON, never as Go's map[...] fmt form.
func TestPrintCSV_NestedCellJSONEncoded(t *testing.T) {
	t.Parallel()
	input := `[{"id":103261,"capital":{"id":1,"lat":42.87,"lng":74.6},"country_languages":[{"code":"ky"}]}]`
	var buf bytes.Buffer
	if err := printCSV(&buf, json.RawMessage(input)); err != nil {
		t.Fatalf("printCSV: %v", err)
	}
	out := buf.String()
	if strings.Contains(out, "map[") {
		t.Errorf("nested cell leaked Go map[...] form:\n%s", out)
	}
	records, err := csv.NewReader(strings.NewReader(out)).ReadAll()
	if err != nil {
		t.Fatalf("output is not valid CSV: %v\noutput:\n%s", err, out)
	}
	// Find the capital column value in the single data row and confirm it is
	// parseable JSON with the expected nested key.
	header, row := records[0], records[1]
	capital := ""
	for i, h := range header {
		if h == "capital" {
			capital = row[i]
		}
	}
	if capital == "" {
		t.Fatalf("no capital column found in %v", header)
	}
	var obj map[string]any
	if err := json.Unmarshal([]byte(capital), &obj); err != nil {
		t.Errorf("capital cell is not valid JSON: %v (cell=%q)", err, capital)
	}
}

